import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';
import { CartService } from '../core/services/cart.service';

interface NavItem {
  label: string;
  path: string;
  icon: string;
  badge?: number;
  exact?: boolean;
}

@Component({
  selector: 'app-storefront-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './storefront-layout.component.html',
  styleUrls: ['./storefront-layout.component.css'],
})
export class StorefrontLayoutComponent {
  auth = inject(AuthService);
  cart = inject(CartService);

  readonly navItems = computed<NavItem[]>(() => {
    const items: NavItem[] = [{ label: 'Catalog', path: '/', icon: '🛍️', exact: true }];
    if (this.auth.isAdmin()) {
      items.push({ label: 'Products', path: '/admin/products', icon: '📦' });
      items.push({ label: 'Orders', path: '/admin/orders', icon: '🧾' });
    } else {
      items.push({ label: 'Cart', path: '/cart', icon: '🛒', badge: this.cart.count() });
      items.push({ label: 'Orders', path: '/orders', icon: '📦' });
    }
    return items;
  });

  logout(): void {
    this.auth.logout();
  }
}
